      "path": "src/modules/projects/routes.js",
      "content": "import express from 'express';
import * as projectsService from './service.js';
import { sendError } from '../../lib/errors.js';

const router = express.Router();

router.get('/', async (req, res) => {
  const projects = await projectsService.getAllProjects();
  if (!projects) return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to fetch projects');
  res.json({ projects });
});

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name || typeof name !== 'string' || name.trim() === '') {
    return sendError(res, 400, 'INVALID_INPUT', 'Name must be a non-empty string');
  }

  const project = await projectsService.createProject(name);
  if (!project) return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to create project');
  res.status(201).json({ project });
});

export default router;
