      "content": "import express from 'express';
import * as membersService from './service.js';
import { sendError } from '../../lib/errors.js';

const router = express.Router();

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || typeof userId !== 'string' || !role || typeof role !== 'string') {
    return sendError(res, 400, 'INVALID_INPUT', 'Both userId and role must be non-empty strings');
  }

  const member = await membersService.addMember(req.params.projectId, userId, role);
  if (!member) return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to add member');
  res.status(201).json({ member });
});

export default router;
